import{c as t,S as i,j as a,m as s}from"./chunks/framework.CuYKfoTy.js";const g=JSON.parse('{"title":"Model","description":"","frontmatter":{},"headers":[],"relativePath":"model.md","filePath":"model.md","lastUpdated":null}'),o={name:"model.md"};function d(l,e,n,r,h,c){return i(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="model" tabindex="-1">Model <a class="header-anchor" href="#model" aria-label="Permalink to &quot;Model&quot;">​</a></h1><p>Two blocks fitted to the 2012 Isiro BDBV line list (n = 52):</p><ol><li><p>Four atomic delay components, each a doubly-censored distribution wrapped in <code>CensoredDistributions.double_interval_censored</code> with <code>interval = 1.0</code> (1-day reporting bins on both endpoints, default <code>primary_event = Uniform(0, 1)</code>).</p></li><li><p>Stratified case-fatality: Bernoulli outcome with a logistic link on HCW status, case definition (Probable vs Confirmed), and standardised age.</p></li></ol><p>Three parametric families are supported (<code>:lognormal</code>, <code>:gamma</code>, <code>:weibull</code>), selected via the <code>family</code> keyword to <code>bdbv_model</code>. The canonical run uses Gamma — lowest WAIC.</p><p><code>bdbv_model_stratified(d; family)</code> adds a <code>β_*_hcw</code> log-mean shift to each delay so HCW and non-HCW cases share the shape parameter but can differ on the central tendency.</p><h1 id="common-parametrisation-across-families" tabindex="-1">Common parametrisation across families <a class="header-anchor" href="#common-parametrisation-across-families" aria-label="Permalink to &quot;Common parametrisation across families&quot;">​</a></h1><p>All three families share a log-mean / log-shape parametrisation so the priors are comparable:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Family</th><th style="text-align:right;">Latent</th><th style="text-align:right;">Distribution constructed</th></tr></thead><tbody><tr><td style="text-align:right;">LogNormal</td><td style="text-align:right;">(log_median, log_sd)</td><td style="text-align:right;"><code>LogNormal(log_median, log_sd)</code></td></tr><tr><td style="text-align:right;">Gamma</td><td style="text-align:right;">(log_mean, log_shape)</td><td style="text-align:right;"><code>Gamma(k, mean/k)</code> with <code>k = exp(log_shape)</code></td></tr><tr><td style="text-align:right;">Weibull</td><td style="text-align:right;">(log_mean, log_shape)</td><td style="text-align:right;"><code>Weibull(α, mean/Γ(1+1/α))</code> with <code>α = exp(log_shape)</code></td></tr></tbody></table><p>For Weibull, <code>log_shape</code> is truncated to <code>(−1, 1)</code> so <code>Γ(1 + 1/α)</code> doesn&#39;t blow up. The Weibull stratified model is not supported.</p><h1 id="compound-delays-via-convolution-post-processing" tabindex="-1">Compound delays via convolution post-processing <a class="header-anchor" href="#compound-delays-via-convolution-post-processing" aria-label="Permalink to &quot;Compound delays via convolution post-processing&quot;">​</a></h1><p>Fitting <code>onset → death</code> and <code>onset → discharge</code> separately alongside their atomic components would violate the per-case identity <code>onset → death = onset → admit + admit → death</code>. So the model fits only the four atomic components:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Component</th><th style="text-align:right;">n</th></tr></thead><tbody><tr><td style="text-align:right;"><code>d_oa</code></td><td style="text-align:right;">onset → admission</td><td style="text-align:right;">40</td></tr><tr><td style="text-align:right;"><code>d_ad</code></td><td style="text-align:right;">admission → death</td><td style="text-align:right;">22</td></tr><tr><td style="text-align:right;"><code>d_ac</code></td><td style="text-align:right;">admission → discharge</td><td style="text-align:right;">15</td></tr><tr><td style="text-align:right;"><code>d_on</code></td><td style="text-align:right;">onset → notification</td><td style="text-align:right;">38</td></tr></tbody></table><p>and derives <code>d_od</code> and <code>d_oc</code> in post-processing as sample-level convolutions. The mean of the convolved marginal equals the sum of the atomic means by linearity of expectation; medians and quantiles come from Monte Carlo (500 samples per posterior draw).</p><p>Per-case censoring noise across the four delays of the same case is treated as independent — see <a href="./limitations">Limitations</a>.</p><h1 id="priors" tabindex="-1">Priors <a class="header-anchor" href="#priors" aria-label="Permalink to &quot;Priors&quot;">​</a></h1><p>Weakly informative, centred on a plausible day count for each delay (<code>prior_scale</code> keyword scales the SDs jointly; default 1.0):</p><table tabindex="0"><thead><tr><th style="text-align:right;">Parameter</th><th style="text-align:right;">Prior</th></tr></thead><tbody><tr><td style="text-align:right;"><code>log_median</code> / <code>log_mean</code> for d_oa</td><td style="text-align:right;">Normal(log 3, <code>prior_scale</code>)</td></tr><tr><td style="text-align:right;"><code>log_median</code> / <code>log_mean</code> for d_ad</td><td style="text-align:right;">Normal(log 6, <code>prior_scale</code>)</td></tr><tr><td style="text-align:right;"><code>log_median</code> / <code>log_mean</code> for d_ac</td><td style="text-align:right;">Normal(log 13, <code>prior_scale</code>)</td></tr><tr><td style="text-align:right;"><code>log_median</code> / <code>log_mean</code> for d_on</td><td style="text-align:right;">Normal(log 7, <code>prior_scale</code>)</td></tr><tr><td style="text-align:right;"><code>log_sd</code> (LogNormal)</td><td style="text-align:right;">half-Normal(0, <code>prior_scale</code>)</td></tr><tr><td style="text-align:right;"><code>log_shape</code> (Gamma)</td><td style="text-align:right;">Normal(0, <code>prior_scale</code>)</td></tr><tr><td style="text-align:right;"><code>log_shape</code> (Weibull)</td><td style="text-align:right;">Normal(0, <code>prior_scale</code>), truncated to (−1, 1)</td></tr><tr><td style="text-align:right;"><code>β_0</code> (CFR baseline)</td><td style="text-align:right;">Normal(0, 2)</td></tr><tr><td style="text-align:right;"><code>β_hcw</code>, <code>β_def</code>, <code>β_age</code></td><td style="text-align:right;">Normal(0, 1)</td></tr><tr><td style="text-align:right;"><code>β_*_hcw</code> (stratified delay shifts)</td><td style="text-align:right;">Normal(0, 0.5)</td></tr></tbody></table><p>The 1.0 default SD on the log-medians gives ≈ ×3-fold prior latitude either way on the central tendency. A 3-scale sensitivity sweep (0.5, 1.0, 2.0) shifts posterior means by &lt; 5%.</p><h1 id="likelihood" tabindex="-1">Likelihood <a class="header-anchor" href="#likelihood" aria-label="Permalink to &quot;Likelihood&quot;">​</a></h1><p>For each atomic delay <code>j ∈ {oa, ad, ac, on}</code>:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dic_j </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> double_interval_censored</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(dist_j; interval </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">observed_j </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Turing</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">filldist</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(dic_j, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">length</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(observed_j))</span></span></code></pre></div><p>CFR block:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">η_i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> β_0 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> β_hcw </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">·</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[HCW_i] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> β_def </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">·</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[Probable_i] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> β_age </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">·</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> age_z_i</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">outcome_i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Bernoulli</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">logistic</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(η_i))</span></span></code></pre></div><p><code>age_z</code> is standardised age (mean 0, SD 1) with the population mean imputed for the 3 of 52 missing ages. <code>logistic(η)</code> is clamped to <code>(1e-10, 1 - 1e-10)</code> so <code>Bernoulli</code>&#39;s domain check doesn&#39;t fail when NUTS proposes large <code>|η|</code> during warmup.</p><h1 id="inference" tabindex="-1">Inference <a class="header-anchor" href="#inference" aria-label="Permalink to &quot;Inference&quot;">​</a></h1><p>NUTS via <code>Turing.jl</code>. Defaults:</p><ul><li><p>1000 post-warmup samples per chain</p></li><li><p>4 chains in parallel (<code>MCMCThreads</code>)</p></li><li><p><code>target_accept = 0.95</code></p></li><li><p><code>AutoForwardDiff()</code> AD backend</p></li><li><p><code>DynamicPPL.InitFromPrior()</code> with a different RNG per chain</p></li><li><p>Seed 20260519 (parent), per-chain seeds derived from a child <code>MersenneTwister</code> so <code>Random.seed!</code> is never called on the global RNG</p></li></ul><p>About 1–2 minutes per family on a laptop. max R̂ ≤ 1.002, min bulk ESS ≥ 3,200, 0 divergent transitions across families.</p><p>The diagnostics are: R̂ (the ratio of between-chain to within-chain variance — values near 1 indicate the four chains agree on the posterior), bulk ESS (effective sample size in the body of the distribution — values in the thousands indicate the chain has explored the posterior efficiently), and divergent transitions (HMC steps that hit numerical instability — zero divergences across all fits means the geometry is well-behaved).</p><h1 id="model-comparison" tabindex="-1">Model comparison <a class="header-anchor" href="#model-comparison" aria-label="Permalink to &quot;Model comparison&quot;">​</a></h1><p>WAIC is computed pointwise: for each observation, the per-draw log-likelihood is evaluated from the per-draw distribution parameters, and WAIC = −2(lppd − p_waic) aggregated across the 167 observations (40 + 22 + 15 + 38 atomic delays + 52 outcomes).</p><p>PSIS-LOO would be preferable but adds dependencies; WAIC is adequate here.</p><h1 id="post-processing" tabindex="-1">Post-processing <a class="header-anchor" href="#post-processing" aria-label="Permalink to &quot;Post-processing&quot;">​</a></h1><p>For each atomic delay the script reports the posterior median, mean, and (for LogNormal) log-SD with 95% CrI. Gamma and Weibull medians come from per-draw <code>quantile(dist, 0.5)</code>.</p><p>For each derived marginal (<code>d_od = d_oa ⊛ d_ad</code>, <code>d_oc = d_oa ⊛ d_ac</code>) the script samples 500 realisations per posterior draw from the convolution and reports median, mean, SD, and 95th percentile with 95% CrI across draws.</p><p>For the CFR block the script reports the log-OR coefficients and the implied marginal CFR at each combination of HCW status and case definition, with age held at its sample mean.</p>`,36)])])}const m=t(o,[["render",d]]);export{g as __pageData,m as default};
